function useScrollReveal(threshold = 0.15) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);

  return { ref, visible };
}

function StarRow() {
  return (
    <div className="flex gap-1 mb-5" aria-label="5 stars">
      {Array.from({ length: 5 }).map((_, i) => (
        <svg
          key={i}
          viewBox="0 0 16 16"
          fill="#B71C1C"
          xmlns="http://www.w3.org/2000/svg"
          className="w-4 h-4"
          aria-hidden="true"
        >
          <path d="M8 1.5l1.545 3.13 3.455.502-2.5 2.437.59 3.44L8 9.385l-3.09 1.624.59-3.44L3 5.132l3.455-.502L8 1.5z" />
        </svg>
      ))}
    </div>
  );
}

function TestimonialCard({
  testimonial,
  index,
  visible,
}: {
  testimonial: Testimonial;
  index: number;
  visible: boolean;
}) {
  return (
    <div
      className="relative flex flex-col bg-white rounded-2xl p-8 h-full"
      style={{
        boxShadow: "0 4px 24px rgba(0,0,0,0.07)",
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(32px)",
        transition: `opacity 0.65s ease ${index * 0.15}s, transform 0.65s ease ${index * 0.15}s`,
      }}
    >
      {/* Giant opening quote mark */}
      <div
        className="absolute top-5 right-7 font-display select-none pointer-events-none"
        style={{
          fontFamily: "var(--font-display)",
          fontSize: "7rem",
          fontWeight: 800,
          color: "#B71C1C",
          opacity: 0.08,
          lineHeight: 1,
        }}
        aria-hidden="true"
      >
        &ldquo;
      </div>

      {/* Star rating */}
      <StarRow />

      {/* Opening quote mark — decorative foreground */}
      <div
        className="font-display leading-none mb-3"
        style={{
          fontFamily: "var(--font-display)",
          fontSize: "3rem",
          fontWeight: 800,
          color: "#B71C1C",
          lineHeight: 0.8,
        }}
        aria-hidden="true"
      >
        &ldquo;
      </div>

      {/* Quote text */}
      <blockquote
        className="font-body flex-1 mb-8"
        style={{
          fontFamily: "var(--font-body)",
          fontSize: "0.975rem",
          fontWeight: 400,
          color: "#424242",
          lineHeight: 1.8,
          fontStyle: "italic",
        }}
      >
        {testimonial.quote}
      </blockquote>

      {/* Divider */}
      <div
        className="w-10 h-0.5 mb-6"
        style={{ backgroundColor: "#B71C1C" }}
        aria-hidden="true"
      />

      {/* Author */}
      <div className="flex items-center gap-4">
        {/* Avatar */}
        <div
          className="w-11 h-11 rounded-full flex items-center justify-center flex-shrink-0"
          style={{ backgroundColor: testimonial.avatarBg }}
          aria-hidden="true"
        >
          <span
            className="text-white font-display text-sm"
            style={{
              fontFamily: "var(--font-display)",
              fontWeight: 700,
              fontSize: "0.8rem",
              letterSpacing: "0.04em",
            }}
          >
            {testimonial.initials}
          </span>
        </div>

        {/* Name + role */}
        <div>
          <p
            className="font-display"
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "0.95rem",
              fontWeight: 700,
              color: "#212121",
              lineHeight: 1.2,
            }}
          >
            {testimonial.name}
          </p>
          <p
            className="font-body mt-0.5"
            style={{
              fontFamily: "var(--font-body)",
              fontSize: "0.8rem",
              fontWeight: 400,
              color: "#757575",
              lineHeight: 1.4,
            }}
          >
            {testimonial.role} · {testimonial.company}
          </p>
        </div>
      </div>
    </div>
  );
}

