'use client';

import { useEffect, useRef, useState } from "react";

interface Stat {
  target: number;
  suffix: string;
  label: string;
  description: string;
  decimals?: boolean;
}

const stats: Stat[] = [
  {
    target: 120,
    suffix: "+",
    label: "Proyectos Entregados",
    description:
      "Sitios web, campañas y producciones entregados a clientes en 14 países.",
  },
  {
    target: 98,
    suffix: "%",
    label: "Retención de Clientes",
    description:
      "Casi todos los clientes que trabajan con nosotros vuelven — no es suerte, es oficio.",
  },
  {
    target: 5,
    suffix: "★",
    label: "Calificación Promedio",
    description:
      "Reseñas consistentes de cinco estrellas en cada línea de servicio y cada proyecto.",
  },
  {
    target: 8,
    suffix: "+",
    label: "Años de Experiencia",
    description:
      "Más de ocho años en la industria ayudando a marcas de todos los tamaños a encontrar su voz.",
  },
];

function useCountUp(target: number, duration: number, active: boolean) {
  const [count, setCount] = useState(0);
  const rafRef = useRef<number>(0);
  const startTimeRef = useRef<number | null>(null);

  useEffect(() => {
    if (!active) return;

    const animate = (timestamp: number) => {
      if (startTimeRef.current === null) {
        startTimeRef.current = timestamp;
      }
      const elapsed = timestamp - startTimeRef.current;
      const progress = Math.min(elapsed / duration, 1);
      // Ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setCount(Math.floor(eased * target));

      if (progress < 1) {
        rafRef.current = requestAnimationFrame(animate);
      } else {
        setCount(target);
      }
    };

    rafRef.current = requestAnimationFrame(animate);

    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [active, target, duration]);

  return count;
}

function StatCard({
  stat,
  index,
  active,
  sectionVisible,
}: {
  stat: Stat;
  index: number;
  active: boolean;
  sectionVisible: boolean;
}) {
  const count = useCountUp(stat.target, 1800, active);

  return (
    <div
      className="relative flex flex-col items-start p-8 bg-white rounded-2xl"
      style={{
        boxShadow: "0 2px 20px rgba(0,0,0,0.06)",
        opacity: sectionVisible ? 1 : 0,
        transform: sectionVisible ? "translateY(0)" : "translateY(32px)",
        transition: `opacity 0.65s ease ${index * 0.14}s, transform 0.65s ease ${index * 0.14}s`,
      }}
    >
      {/* Decorative top-left corner accent */}
      <div
        className="absolute top-0 left-0 w-1 h-12 rounded-tl-2xl rounded-bl-lg"
        style={{ backgroundColor: "#B71C1C" }}
        aria-hidden="true"
      />

      {/* Number */}
      <div className="flex items-end gap-0.5 mb-3 pl-4">
        <span
          className="font-display leading-none tabular-nums"
          style={{
            fontFamily: "var(--font-display)",
            fontSize: "clamp(3rem, 6vw, 5rem)",
            fontWeight: 800,
            color: "#B71C1C",
            lineHeight: 1,
            letterSpacing: "-0.03em",
          }}
        >
          {count}
        </span>
        <span
          className="font-display leading-none mb-1"
          style={{
            fontFamily: "var(--font-display)",
            fontSize: "clamp(1.5rem, 3vw, 2.5rem)",
            fontWeight: 800,
            color: "#D32F2F",
            lineHeight: 1,
          }}
        >
          {stat.suffix}
        </span>
      </div>

      {/* Label */}
      <h3
        className="font-display mb-2 pl-4"
        style={{
          fontFamily: "var(--font-display)",
          fontSize: "1rem",
          fontWeight: 700,
          color: "#212121",
          letterSpacing: "-0.01em",
        }}
      >
        {stat.label}
      </h3>

      {/* Description */}
      <p
        className="font-body pl-4"
        style={{
          fontFamily: "var(--font-body)",
          fontSize: "0.875rem",
          fontWeight: 400,
          color: "#757575",
          lineHeight: 1.7,
        }}
      >
        {stat.description}
      </p>
    </div>
  );
}

export default function Stats() {
  const sectionRef = useRef<HTMLDivElement>(null);
  const [sectionVisible, setSectionVisible] = useState(false);
  const [countersActive, setCountersActive] = useState(false);

  useEffect(() => {
    const el = sectionRef.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setSectionVisible(true);
          // Slight delay so cards animate in before counters start
          setTimeout(() => setCountersActive(true), 400);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  return (
    <section
      id="stats"
      className="py-24 overflow-hidden"
      style={{ backgroundColor: "#F5F5F5" }}
    >
      <div className="max-w-7xl mx-auto px-6 lg:px-8" ref={sectionRef}>

        {/* Section header */}
        <div
          className="max-w-2xl mb-16"
          style={{
            opacity: sectionVisible ? 1 : 0,
            transform: sectionVisible ? "translateY(0)" : "translateY(24px)",
            transition: "opacity 0.7s ease, transform 0.7s ease",
          }}
        >
          <div className="flex items-center gap-2 mb-4">
            <div className="w-8 h-0.5" style={{ backgroundColor: "#B71C1C" }} />
            <span
              className="text-xs uppercase tracking-widest font-body"
              style={{
                fontFamily: "var(--font-body)",
                fontWeight: 500,
                color: "#B71C1C",
                letterSpacing: "0.15em",
              }}
            >
              Por Qué ReckTrack
            </span>
          </div>

          <h2
            className="font-display mb-6"
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "clamp(2rem, 4vw, 3rem)",
              fontWeight: 800,
              color: "#212121",
              lineHeight: 1.1,
              letterSpacing: "-0.02em",
            }}
          >
            Los números no mienten.{" "}
            <span style={{ color: "#B71C1C" }}>Los nuestros hablan fuerte.</span>
          </h2>

          <p
            className="font-body"
            style={{
              fontFamily: "var(--font-body)",
              fontSize: "1.05rem",
              fontWeight: 400,
              color: "#757575",
              lineHeight: 1.75,
            }}
          >
            Ocho años de ejecución implacable, medidos en entregables,
            relaciones y resultados que se multiplican.
          </p>
        </div>

        {/* Stats grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {stats.map((stat, i) => (
            <StatCard
              key={stat.label}
              stat={stat}
              index={i}
              active={countersActive}
              sectionVisible={sectionVisible}
            />
          ))}
        </div>

        {/* Bottom decorative band */}
        <div
          className="mt-20 flex items-center gap-6"
          style={{
            opacity: sectionVisible ? 1 : 0,
            transition: "opacity 0.7s ease 0.8s",
          }}
        >
          <div className="flex-1 h-px" style={{ backgroundColor: "#E0E0E0" }} />
          <p
            className="font-display text-center px-4 whitespace-nowrap"
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "0.85rem",
              fontWeight: 600,
              color: "#B71C1C",
              letterSpacing: "0.12em",
              textTransform: "uppercase",
            }}
          >
            Con la confianza de fundadores, CMOs y directores creativos de todo el mundo
          </p>
          <div className="flex-1 h-px" style={{ backgroundColor: "#E0E0E0" }} />
        </div>
      </div>
    </section>
  );
}
