'use client';

import { useEffect, useRef, useState, FormEvent } from "react";

type FormStatus = "idle" | "sending" | "success" | "error";

interface FormFields {
  name: string;
  email: string;
  service: string;
  message: string;
}

const serviceOptions = [
  "Desarrollo Web",
  "Contenido Audiovisual",
  "Fotografía",
  "Campaña de Marketing",
  "Servicio Integral",
  "Otro",
];

const contactDetails = [
  {
    label: "Correo",
    value: "hello@recktrack.com",
    icon: (
      <svg viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" aria-hidden="true">
        <rect x="2" y="5" width="16" height="11" rx="2" stroke="#B71C1C" strokeWidth="1.6" />
        <path d="M2 7l8 5 8-5" stroke="#B71C1C" strokeWidth="1.6" strokeLinecap="round" />
      </svg>
    ),
  },
  {
    label: "Teléfono",
    value: "+1 (555) 800-RECK",
    icon: (
      <svg viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" aria-hidden="true">
        <path
          d="M4 3h3.5l1.5 4-2 1.5a10 10 0 004.5 4.5L13 11l4 1.5V16a1 1 0 01-1 1C6.5 17 3 10.5 3 4a1 1 0 011-1z"
          stroke="#B71C1C"
          strokeWidth="1.6"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </svg>
    ),
  },
  {
    label: "Ubicación",
    value: "Nueva York · São Paulo · Lisboa",
    icon: (
      <svg viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" aria-hidden="true">
        <path
          d="M10 2a6 6 0 016 6c0 4-6 10-6 10S4 12 4 8a6 6 0 016-6z"
          stroke="#B71C1C"
          strokeWidth="1.6"
          strokeLinejoin="round"
        />
        <circle cx="10" cy="8" r="2" stroke="#B71C1C" strokeWidth="1.6" />
      </svg>
    ),
  },
];

function useScrollReveal(threshold = 0.12) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);

  return { ref, visible };
}

const inputClass =
  "w-full border border-gray-200 rounded-lg px-4 py-3 font-body text-sm text-brand-text bg-white placeholder-brand-muted focus:outline-none focus:ring-2 focus:ring-brand-primary focus:border-transparent transition-all duration-300 hover:border-gray-300";

export default function Contact() {
  const { ref, visible } = useScrollReveal();
  const [fields, setFields] = useState<FormFields>({
    name: "",
    email: "",
    service: "",
    message: "",
  });
  const [status, setStatus] = useState<FormStatus>("idle");
  const [errors, setErrors] = useState<Partial<FormFields>>({});

  const validate = (): boolean => {
    const newErrors: Partial<FormFields> = {};
    if (!fields.name.trim()) newErrors.name = "El nombre es obligatorio.";
    if (!fields.email.trim()) {
      newErrors.email = "El email es obligatorio.";
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(fields.email)) {
      newErrors.email = "Por favor, ingresa un email válido.";
    }
    if (!fields.message.trim()) newErrors.message = "El mensaje es obligatorio.";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFields((prev) => ({ ...prev, [name]: value }));
    // Clear error on change
    if (errors[name as keyof FormFields]) {
      setErrors((prev) => ({ ...prev, [name]: undefined }));
    }
  };

  const handleSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!validate()) return;
    setStatus("sending");
    // Simulate network delay — replace with real API call
    await new Promise((res) => setTimeout(res, 1600));
    setStatus("success");
    setFields({ name: "", email: "", service: "", message: "" });
  };

  return (
    <section id="contact" className="py-24 bg-white">
      <div className="max-w-7xl mx-auto px-6 lg:px-8">

        {/* Section header */}
        <div
          ref={ref}
          className="max-w-2xl mb-16"
          style={{
            opacity: visible ? 1 : 0,
            transform: visible ? "translateY(0)" : "translateY(24px)",
            transition: "opacity 0.7s ease, transform 0.7s ease",
          }}
        >
          <div className="flex items-center gap-2 mb-4">
            <div className="w-8 h-0.5" style={{ backgroundColor: "#B71C1C" }} />
            <span
              className="text-xs uppercase tracking-widest font-body"
              style={{
                fontFamily: "var(--font-body)",
                fontWeight: 500,
                color: "#B71C1C",
                letterSpacing: "0.15em",
              }}
            >
              Contáctanos
            </span>
          </div>

          <h2
            className="font-display mb-5"
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "clamp(2.2rem, 5vw, 3.5rem)",
              fontWeight: 800,
              color: "#212121",
              lineHeight: 1.05,
              letterSpacing: "-0.03em",
            }}
          >
            ¿Listo para{" "}
            <span style={{ color: "#B71C1C" }}>crecer?</span>
          </h2>

          <p
            className="font-body"
            style={{
              fontFamily: "var(--font-body)",
              fontSize: "1.05rem",
              fontWeight: 400,
              color: "#757575",
              lineHeight: 1.75,
            }}
          >
            Cuéntanos sobre tu proyecto y te responderemos en un día hábil.
            Sin rodeos, sin presión — solo una conversación real sobre lo que
            necesitas.
          </p>
        </div>

        {/* Two-column layout: form left, info right */}
        <div
          className="grid grid-cols-1 lg:grid-cols-5 gap-12 lg:gap-16 items-start"
          style={{
            opacity: visible ? 1 : 0,
            transform: visible ? "translateY(0)" : "translateY(32px)",
            transition: "opacity 0.7s ease 0.15s, transform 0.7s ease 0.15s",
          }}
        >
          {/* ── Form (3/5 width on lg) ────────────────────────────── */}
          <div className="lg:col-span-3">
            {status === "success" ? (
              <div
                className="flex flex-col items-center justify-center text-center py-20 px-8 rounded-2xl"
                style={{ backgroundColor: "#F8EEEE" }}
              >
                {/* Check mark */}
                <div
                  className="w-16 h-16 rounded-full flex items-center justify-center mb-6"
                  style={{ backgroundColor: "#B71C1C" }}
                >
                  <svg
                    viewBox="0 0 24 24"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                    className="w-8 h-8"
                    aria-hidden="true"
                  >
                    <path
                      d="M5 12l5 5L19 7"
                      stroke="white"
                      strokeWidth="2.5"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                </div>
                <h3
                  className="font-display mb-3"
                  style={{
                    fontFamily: "var(--font-display)",
                    fontSize: "1.5rem",
                    fontWeight: 800,
                    color: "#212121",
                  }}
                >
                  ¡Mensaje recibido!
                </h3>
                <p
                  className="font-body"
                  style={{
                    fontFamily: "var(--font-body)",
                    fontSize: "0.95rem",
                    color: "#757575",
                    lineHeight: 1.7,
                    maxWidth: "28rem",
                  }}
                >
                  Gracias por contactarnos. Un miembro de nuestro equipo se
                  comunicará contigo en un día hábil.
                </p>
                <button
                  onClick={() => setStatus("idle")}
                  className="mt-8 btn-ghost"
                  style={{ fontFamily: "var(--font-display)" }}
                >
                  Enviar otro mensaje
                </button>
              </div>
            ) : (
              <form onSubmit={handleSubmit} noValidate className="space-y-5">
                {/* Name + Email row */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                  {/* Name */}
                  <div>
                    <label
                      htmlFor="contact-name"
                      className="block font-body text-xs font-600 mb-1.5 uppercase tracking-wider"
                      style={{
                        fontFamily: "var(--font-body)",
                        fontWeight: 600,
                        color: "#212121",
                        letterSpacing: "0.08em",
                        fontSize: "0.7rem",
                      }}
                    >
                      Nombre Completo <span style={{ color: "#B71C1C" }}>*</span>
                    </label>
                    <input
                      id="contact-name"
                      type="text"
                      name="name"
                      value={fields.name}
                      onChange={handleChange}
                      placeholder="Carolina Ferreira"
                      autoComplete="name"
                      className={inputClass}
                      style={{ fontFamily: "var(--font-body)" }}
                      aria-describedby={errors.name ? "error-name" : undefined}
                      aria-invalid={!!errors.name}
                    />
                    {errors.name && (
                      <p
                        id="error-name"
                        className="mt-1.5 text-xs font-body"
                        style={{ color: "#B71C1C", fontFamily: "var(--font-body)" }}
                        role="alert"
                      >
                        {errors.name}
                      </p>
                    )}
                  </div>

                  {/* Email */}
                  <div>
                    <label
                      htmlFor="contact-email"
                      className="block font-body text-xs font-600 mb-1.5 uppercase tracking-wider"
                      style={{
                        fontFamily: "var(--font-body)",
                        fontWeight: 600,
                        color: "#212121",
                        letterSpacing: "0.08em",
                        fontSize: "0.7rem",
                      }}
                    >
                      Correo Electrónico <span style={{ color: "#B71C1C" }}>*</span>
                    </label>
                    <input
                      id="contact-email"
                      type="email"
                      name="email"
                      value={fields.email}
                      onChange={handleChange}
                      placeholder="you@company.com"
                      autoComplete="email"
                      className={inputClass}
                      style={{ fontFamily: "var(--font-body)" }}
                      aria-describedby={errors.email ? "error-email" : undefined}
                      aria-invalid={!!errors.email}
                    />
                    {errors.email && (
                      <p
                        id="error-email"
                        className="mt-1.5 text-xs font-body"
                        style={{ color: "#B71C1C", fontFamily: "var(--font-body)" }}
                        role="alert"
                      >
                        {errors.email}
                      </p>
                    )}
                  </div>
                </div>

                {/* Service dropdown */}
                <div>
                  <label
                    htmlFor="contact-service"
                    className="block font-body text-xs font-600 mb-1.5 uppercase tracking-wider"
                    style={{
                      fontFamily: "var(--font-body)",
                      fontWeight: 600,
                      color: "#212121",
                      letterSpacing: "0.08em",
                      fontSize: "0.7rem",
                    }}
                  >
                    Servicio de Interés
                  </label>
                  <select
                    id="contact-service"
                    name="service"
                    value={fields.service}
                    onChange={handleChange}
                    className={inputClass}
                    style={{ fontFamily: "var(--font-body)", cursor: "pointer" }}
                  >
                    <option value="">Selecciona un servicio…</option>
                    {serviceOptions.map((opt) => (
                      <option key={opt} value={opt}>
                        {opt}
                      </option>
                    ))}
                  </select>
                </div>

                {/* Message */}
                <div>
                  <label
                    htmlFor="contact-message"
                    className="block font-body text-xs font-600 mb-1.5 uppercase tracking-wider"
                    style={{
                      fontFamily: "var(--font-body)",
                      fontWeight: 600,
                      color: "#212121",
                      letterSpacing: "0.08em",
                      fontSize: "0.7rem",
                    }}
                  >
                      Tu Mensaje <span style={{ color: "#B71C1C" }}>*</span>
                  </label>
                  <textarea
                    id="contact-message"
                    name="message"
                    value={fields.message}
                    onChange={handleChange}
                    rows={5}
                    placeholder="Cuéntanos sobre tu proyecto, objetivos, plazos y presupuesto…"
                    className={inputClass}
                    style={{
                      fontFamily: "var(--font-body)",
                      resize: "vertical",
                      minHeight: "130px",
                    }}
                    aria-describedby={errors.message ? "error-message" : undefined}
                    aria-invalid={!!errors.message}
                  />
                  {errors.message && (
                    <p
                      id="error-message"
                      className="mt-1.5 text-xs font-body"
                      style={{ color: "#B71C1C", fontFamily: "var(--font-body)" }}
                      role="alert"
                    >
                      {errors.message}
                    </p>
                  )}
                </div>

                {/* Submit */}
                <button
                  type="submit"
                  disabled={status === "sending"}
                  className="w-full sm:w-auto btn-primary disabled:opacity-70 disabled:cursor-not-allowed disabled:scale-100"
                  style={{ fontFamily: "var(--font-display)", fontWeight: 700 }}
                >
                  {status === "sending" ? (
                    <span className="flex items-center gap-2">
                      {/* Spinner */}
                      <svg
                        className="animate-spin w-4 h-4 text-white"
                        viewBox="0 0 24 24"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                        aria-hidden="true"
                      >
                        <circle
                          cx="12"
                          cy="12"
                          r="10"
                          stroke="currentColor"
                          strokeWidth="3"
                          strokeOpacity="0.25"
                        />
                        <path
                          d="M22 12a10 10 0 00-10-10"
                          stroke="currentColor"
                          strokeWidth="3"
                          strokeLinecap="round"
                        />
                      </svg>
                      Enviando…
                    </span>
                  ) : (
                    <span className="flex items-center gap-2">
                      Enviar Mensaje
                      <svg
                        viewBox="0 0 16 16"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                        className="w-4 h-4"
                        aria-hidden="true"
                      >
                        <path
                          d="M3 8h10M9 4l4 4-4 4"
                          stroke="white"
                          strokeWidth="1.8"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        />
                      </svg>
                    </span>
                  )}
                </button>

                <p
                  className="font-body text-xs"
                  style={{
                    fontFamily: "var(--font-body)",
                    color: "#9E9E9E",
                    lineHeight: 1.6,
                  }}
                >
                  Respetamos tu privacidad. Tu información nunca es compartida
                  ni vendida.
                </p>
              </form>
            )}
          </div>

          {/* ── Contact info (2/5 width on lg) ───────────────────── */}
          <div className="lg:col-span-2 flex flex-col gap-8">

            {/* Contact details */}
            <div
              className="rounded-2xl p-8"
              style={{ backgroundColor: "#F5F5F5" }}
            >
              <h3
                className="font-display mb-6"
                style={{
                  fontFamily: "var(--font-display)",
                  fontSize: "1.1rem",
                  fontWeight: 700,
                  color: "#212121",
                }}
              >
                Detalles de Contacto
              </h3>
              <div className="flex flex-col gap-5">
                {contactDetails.map((item) => (
                  <div key={item.label} className="flex items-start gap-3">
                    <div
                      className="w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 mt-0.5"
                      style={{ backgroundColor: "#F8EEEE" }}
                    >
                      {item.icon}
                    </div>
                    <div>
                      <p
                        className="font-body text-xs uppercase tracking-wider mb-0.5"
                        style={{
                          fontFamily: "var(--font-body)",
                          fontWeight: 600,
                          color: "#9E9E9E",
                          letterSpacing: "0.1em",
                          fontSize: "0.65rem",
                        }}
                      >
                        {item.label}
                      </p>
                      <p
                        className="font-body text-sm"
                        style={{
                          fontFamily: "var(--font-body)",
                          fontWeight: 500,
                          color: "#212121",
                        }}
                      >
                        {item.value}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Response time promise */}
            <div
              className="rounded-2xl p-8 relative overflow-hidden"
              style={{ backgroundColor: "#B71C1C" }}
            >
              {/* Background shape */}
              <div
                className="absolute -bottom-8 -right-8 w-36 h-36 rounded-full opacity-20"
                style={{ backgroundColor: "#7F0000" }}
                aria-hidden="true"
              />
              <div
                className="absolute top-4 right-4 w-12 h-12 rounded-full opacity-15"
                style={{ backgroundColor: "#FF5252" }}
                aria-hidden="true"
              />

              <svg
                viewBox="0 0 24 24"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
                className="w-8 h-8 mb-4 relative z-10"
                aria-hidden="true"
              >
                <circle cx="12" cy="12" r="9" stroke="white" strokeWidth="1.8" strokeOpacity="0.6" />
                <path d="M12 7v5l3 3" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
              </svg>

              <h3
                className="font-display text-white mb-2 relative z-10"
                style={{
                  fontFamily: "var(--font-display)",
                  fontSize: "1.1rem",
                  fontWeight: 700,
                  lineHeight: 1.2,
                }}
              >
                Respondemos en 24 horas
              </h3>
              <p
                className="font-body relative z-10"
                style={{
                  fontFamily: "var(--font-body)",
                  fontSize: "0.875rem",
                  fontWeight: 400,
                  color: "rgba(255,255,255,0.75)",
                  lineHeight: 1.6,
                }}
              >
                Envía tu brief hoy y nuestro equipo de estrategia tendrá una
                propuesta personalizada en tu bandeja de entrada mañana.
              </p>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
